// figma-import-mypage.js
// マイページ画面を Figma に追加します。

(async () => {
  const IMG_MYPAGE = "data:image/png;base64,";

  // 03_マイページ
  const frame = figma.createFrame();
  frame.name = "03_マイページ";
  frame.resize(1440, 900);
  frame.x = 0;
  frame.y = 0;
  const imgData_mypage = IMG_MYPAGE.replace(/^data:image\/png;base64,/, "");
  const bytes_mypage = Uint8Array.from(atob(imgData_mypage), c => c.charCodeAt(0));
  const img_mypage = figma.createImage(bytes_mypage);
  frame.fills = [{ type: "IMAGE", scaleMode: "FILL", imageHash: img_mypage.hash }];

  figma.currentPage.selection = [frame];
  figma.viewport.scrollAndZoomIntoView([frame]);
  figma.closePlugin("✅ 03_マイページ をFigmaに追加しました！");
})();
